mapper.select:
SELECT n.id, n.user_id, n.name, n.os_type, n.status, n.last_seen, n.created_at, n.agent_id,
       n.agent_secret_hash, n.agent_secret_issued_at, n.update_status,
       n.update_current_sha, n.update_latest_sha, n.update_message, n.update_checked_at
FROM nodes n
WHERE n.id = #{nodeId}
  AND (
      n.user_id = #{userId}
      OR EXISTS (
          SELECT 1
          FROM team_nodes tn
          JOIN team_members tm ON tm.team_id = tn.team_id
          WHERE tn.node_id = n.id
            AND tm.user_id = #{userId}
            AND tm.status = 'ACTIVE'
      )
  )

mapper.update:
UPDATE nodes
SET status = #{status}
WHERE id = #{id}
  AND status <> 'D'

UPDATE nodes
SET status = 'D'
WHERE id = #{id}
